// // This module calculates the sum of two input bits (A and B) and a carry-in bit (CI), but outputs the sum as the negation of the actual sum and the carry-out as the actual carry-out.
module top_module(
    input A,
    input B,
    input CI,
    output SUM,
    output COUT_N,
    input VPB,
    input VPWR,
    input VGND,
    input VNB
);wire a_xor_b = A ^ B;
wire sum = a_xor_b ^ CI;
wire carry_out = (A & B) | (a_xor_b & CI);

assign SUM = sum;
assign COUT_N = ~carry_out;

endmodule
